function renderMap(flights) {
    // Locate the map container
    let mapContainer = root_element.querySelector('#recent-flights-map');
    if (!mapContainer) {
        console.error("Map container not found!");
        return;
    }

    // Initialize the map
    let map = L.map(mapContainer);

    let tileLayerSatellite = L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
    	attribution: 'Tiles &copy; Esri &mdash; Source: Esri, i-cubed, USDA, USGS, AEX, GeoEye, Getmapping, Aerogrid, IGN, IGP, UPR-EGP, and the GIS User Community'
    });
    
    let tileLayerTerrain = L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/NatGeo_World_Map/MapServer/tile/{z}/{y}/{x}', {
    	attribution: 'Tiles &copy; Esri &mdash; National Geographic, Esri, DeLorme, NAVTEQ, UNEP-WCMC, USGS, NASA, ESA, METI, NRCAN, GEBCO, NOAA, iPC',
    	maxZoom: 16
    });
    
    // Add the OpenStreetMap tile layer
    let tileLayerOSM = L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png', {
        maxZoom: 19,
        attribution: '&copy; <a href="http://www.openstreetmap.org/copyright">OpenStreetMap</a>'
    });

    // Add the layers control
    let baseMaps = {
        "Satellite": tileLayerSatellite,
        "Terrain": tileLayerTerrain,
        "OpenStreetMap": tileLayerOSM,
    };

    // Add the default tile layer to the map (set Satellite as default)
    tileLayerSatellite.addTo(map);
    
    L.control.layers(baseMaps).addTo(map);
    // Create a custom cluster group with a custom icon
    let markers = L.markerClusterGroup({
        showCoverageOnHover: false, // Disable the hover polygon
        iconCreateFunction: function (cluster) {
            // Get the count of markers in this cluster
            let count = cluster.getChildCount();

            // Define the cluster's visual appearance
            return L.divIcon({
                html: `
                    <div class="cluster_icon">
                        <b>${count}</b>
                    </div>
                `,
                className: '', // Clear the default class
                iconSize: [40, 40]
            });
        }
    });

    // Loop through flights and add markers
    flights.forEach(flight => {
        if (flight.location) {
            try {
                // Parse GeoJSON data
                let locationData = JSON.parse(flight.location);
                if (locationData.geometry && locationData.geometry.type === "Point") {
                    let coords = locationData.geometry.coordinates;

                    // Coordinates in GeoJSON are [lng, lat], Leaflet uses [lat, lng]
                    let marker = L.marker([coords[1], coords[0]])
                        .bindPopup(`
                            <b>Flight ID:</b> <a href="/app/flight/${flight.name}">${flight.name}</a><br>
                            <b>Aircraft:</b> ${flight.aircraft}<br>
                            <b>Takeoff:</b> ${flight.takeoff_time}<br>
                            <b>Landing:</b> ${flight.landing_time}
                        `);

                    // Add marker to the cluster group
                    markers.addLayer(marker);
                }
            } catch (error) {
                console.error("Invalid location data for flight:", flight.name, error);
            }
        }
    });

    // Add the marker cluster group to the map
    map.addLayer(markers);

    // Adjust the map view to fit all markers
    let bounds = markers.getBounds();
    if (bounds.isValid()) {
        map.fitBounds(bounds);
    } else {
        // If no valid bounds, set default view
        map.setView([0, 0], 2); // World view
    }
}

frappe.require([
    "https://cdnjs.cloudflare.com/ajax/libs/leaflet.markercluster/1.5.3/leaflet.markercluster.js",
    "https://cdnjs.cloudflare.com/ajax/libs/leaflet.markercluster/1.5.3/MarkerCluster.css",
    "https://cdnjs.cloudflare.com/ajax/libs/leaflet.markercluster/1.5.3/MarkerCluster.Default.css"
], function() {
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Flight",
            fields: [
                "name",
                "takeoff_time",
                "landing_time",
                "aircraft",
                "location"
            ],
            filters: [
                ["is_simulator_flight", "=", 0],
                ["landing_time", "is", "set"]
            ],
            order_by: "modified desc",
            limit_page_length: 100
        },
        callback: function (response) {
            if (response.message) {
                renderMap(response.message);
            }
        }
    });
});

style:
#recent-flights-map {
    width: 100%;
    height: 400px;
    z-index: 0;
}

.cluster_icon {
    background-color: rgba(0, 123, 255, 0.8); 
    color: white; 
    border-radius: 50%; 
    width: 40px; 
    height: 40px; 
    display: flex; 
    align-items: center; 
    justify-content: center; 
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.2);
}
